    nutrition: { en: 'Per serving (est.): ~130 kcal · Carbs 18 g · Fat 4 g · Protein 6 g', ua: 'На порцію (прибл.): ~130 ккал · Вуглеводи 18 г · Жири 4 г · Білки 6 г' },
    meta: { prep: { en: '3 min', ua: '3 хв' }, cook: { en: '15 min', ua: '15 хв' }, serves: { en: 'Serves 3', ua: '3 порції' } },
    ingredients: { en: ['1 cup water','2 eggs','½–¾ cup oat flour','1 tbsp coconut flour','1 tsp baking powder','1 pinch salt','1 tsp stevia','2–3 tbsp pumpkin purée','1 tsp cinnamon','1 pinch vanilla','1 heaped tbsp cocoa (fat-reduced)','2 tbsp isomalt','2 tsp water'], ua: ['1 склянка води','2 яйця','½–¾ склянки вівсяного борошна','1 ст. л. кокосового борошна','1 ч. л. розпушувача','1 щіпка солі','1 ч. л. стевії','2–3 ст. л. гарбузового пюре','1 ч. л. кориці','1 щіпка ваніліну','1 ст. л. з горою какао (знежиреного)','2 ст. л. ізомальту','2 ч. л. води'] },
    method: { en: ['Mix the dry and wet ingredients separately.','Combine, adding a little water for the right consistency.','Let the batter swell.','Pour onto a hot pan and fry both sides.','Make the sauce from cocoa and isomalt with water over the heat.','Drizzle over the pancakes, scatter with nuts and stack.'], ua: ['Змішайте окремо сухі та вологі інгредієнти.','З’єднайте, додаючи трохи води для потрібної консистенції.','Дайте тісту набухнути.','Вилийте на гарячу сковороду та смажте з обох боків.','Приготуйте соус із какао та ізомальту з водою на вогні.','Полийте млинці соусом, посипте горіхами та складіть стопкою.'] }
