    nutrition: { en: 'Per cookie (est.): ~65 kcal · Carbs 9 g · Fat 2 g · Protein 3 g', ua: 'На 1 печиво (прибл.): ~65 ккал · Вуглеводи 9 г · Жири 2 г · Білки 3 г' },
